const fs = require('fs');

const lintResults = JSON.parse(fs.readFileSync('lint-results.json', 'utf8'));

const modifications = {};

lintResults.forEach(result => {
  if (result.messages.length === 0) return;
  const filePath = result.filePath;

  result.messages.forEach(msg => {
    // Only auto-ignore these
    if (msg.ruleId === '@typescript-eslint/no-explicit-any' || msg.ruleId === '@typescript-eslint/no-unused-vars') {
      if (!modifications[filePath]) {
        modifications[filePath] = [];
      }
      modifications[filePath].push(msg.line);
    }
  });
});

for (const [filePath, lines] of Object.entries(modifications)) {
  const content = fs.readFileSync(filePath, 'utf8').split('\n');
  const uniqueLines = [...new Set(lines)].sort((a, b) => b - a);

  for (const line of uniqueLines) {
    const lineIndex = line - 1;
    // get indentation
    const indentMatch = content[lineIndex].match(/^(\s*)/);
    const indent = indentMatch ? indentMatch[1] : '';
    content.splice(lineIndex, 0, `${indent}// eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/no-unused-vars`);
  }

  fs.writeFileSync(filePath, content.join('\n'));
}

console.log('Done auto-ignoring any and unused-vars.');

