            >
              <svg className="w-5 h-5 mr-3 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>
              Подписка
            </button>
            <button
              onClick={() => handleAddBlock("BannerSlider")}
              className="w-full bg-blue-50 border border-blue-200 text-blue-700 rounded-md p-3 text-sm font-medium hover:bg-blue-100 transition-colors text-left flex items-center"
            >
              <svg className="w-5 h-5 mr-3 text-blue-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
              Баннер-карусель
            </button>
            <button
              onClick={() => handleAddBlock("ProductGrid")}
              className="w-full bg-blue-50 border border-blue-200 text-blue-700 rounded-md p-3 text-sm font-medium hover:bg-blue-100 transition-colors text-left flex items-center"
            >
              <svg className="w-5 h-5 mr-3 text-blue-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" /></svg>
              Сетка товаров
            </button>
            <button
              onClick={() => handleAddBlock("Accordion")}
              className="w-full bg-gray-50 border border-gray-200 rounded-md p-3 text-sm font-medium hover:bg-gray-100 transition-colors text-left flex items-center"
            >
              <svg className="w-5 h-5 mr-3 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
              Аккордеон
            </button>
            <button
              onClick={() => handleAddBlock("DropdownMenu")}
              className="w-full bg-gray-50 border border-gray-200 rounded-md p-3 text-sm font-medium hover:bg-gray-100 transition-colors text-left flex items-center"
            >
              <svg className="w-5 h-5 mr-3 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
              Меню
            </button>
            <button
              onClick={() => handleAddBlock("PopupBanner")}
              className="w-full bg-gray-50 border border-gray-200 rounded-md p-3 text-sm font-medium hover:bg-gray-100 transition-colors text-left flex items-center"
            >
              <svg className="w-5 h-5 mr-3 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" /></svg>
              Попап
            </button>
          </div>
        </MotionDiv>

        {/* Центр - Холст */}
        <div 
          className="flex-1 overflow-y-auto p-8 relative"
          onClick={() => selectBlock(null)}
        >
          <DndContext
            sensors={sensors}
            collisionDetection={closestCenter}
            onDragEnd={handleDragEnd}
          >
            <div className="max-w-4xl mx-auto min-h-full bg-white shadow-sm border border-gray-200 p-2">
              {blocks.length === 0 ? (
                <div className="flex items-center justify-center h-full min-h-[500px] text-gray-400">
                  Добавьте блоки из палитры слева
                </div>
              ) : (
                <SortableContext 
                  items={blocks.map(b => b.id)} 
                  strategy={verticalListSortingStrategy}
                >
                  <div className="flex flex-col gap-2">
                    {blocks.map((block) => (
                      <SortableBlock
                        key={block.id}
                        block={block}
                        isSelected={selectedBlockId === block.id}
                        onSelect={selectBlock}
                        onRemove={removeBlock}
                      />
                    ))}
                  </div>
                </SortableContext>
              )}
            </div>
          </DndContext>
        </div>

        {/* Правая колонка - Настройки */}
        <div className="w-80 bg-white border-l border-gray-200 p-4 flex flex-col overflow-y-auto">
          <h2 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-4">Настройки</h2>

          {selectedBlock ? (
            <div className="space-y-4">
              <div className="bg-blue-50 text-blue-800 text-xs font-medium px-2 py-1 rounded-md inline-block mb-2">
                Тип: {selectedBlock.type}
              </div>

              <div className="space-y-4">
                {Object.keys(selectedBlock.content).map((key) => (
                  <div key={key}>
                    <label className="block text-sm font-medium text-gray-700 mb-1 capitalize">
                      {key}
                    </label>
                    {typeof (selectedBlock.content as any)[key] === "string" ? (
                      <div className="relative">
                        <input
                          type="text"
                          value={(selectedBlock.content as any)[key]}
                          onChange={(e) =>
                            updateBlock(selectedBlock.id, { content: { ...selectedBlock.content, [key]: e.target.value } } as any)
                          }
                          className="w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500"
                        />
                        {key === 'text' && (
                          <button 
                            onClick={() => handleGenerateText(selectedBlock.id, (selectedBlock.content as any)[key])}
                            disabled={isGenerating}
                            className="absolute inset-y-0 right-0 flex items-center pr-3 text-blue-500 hover:text-blue-700 disabled:opacity-50"
                            title="Сгенерировать с помощью AI"
                          >
                            <Wand2 className="w-4 h-4" />
                          </button>
                        )}
                        {key === 'src' && selectedBlock.type === 'Image' && (
                          <div className="mt-2">
                            <label htmlFor={`image-upload-${selectedBlock.id}`} className="cursor-pointer text-sm text-blue-600 hover:text-blue-500">
                              Загрузить фото
                            </label>
                            <input
                              id={`image-upload-${selectedBlock.id}`}
                              type="file"
                              accept="image/*"
                              className="sr-only"
                              onChange={(e) => handleImageUpload(e, selectedBlock.id)}
                            />
                          </div>
                        )}
                      </div>
                    ) : (
                      <span className="text-sm text-gray-400">Сложный тип</span>
                    )}
                  </div>
                ))}
              </div>
              <div className="space-y-4 pt-4 border-t">
                <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider">Адаптивность</h3>
                <div className="flex items-center justify-between">
                  <label className="text-sm font-medium text-gray-700">Скрыть на моб. (hideOnMobile)</label>
                  <input
                    type="checkbox"
                    checked={selectedBlock.settings?.hideOnMobile || false}
                    onChange={(e) => updateBlock(selectedBlock.id, {}, {}, { ...selectedBlock.settings, hideOnMobile: e.target.checked })}
                    className="h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded"
                  />
                </div>
                <div className="flex items-center justify-between">
                  <label className="text-sm font-medium text-gray-700">Скрыть на десктопе (hideOnDesktop)</label>
                  <input
                    type="checkbox"
                    checked={selectedBlock.settings?.hideOnDesktop || false}
                    onChange={(e) => updateBlock(selectedBlock.id, {}, {}, { ...selectedBlock.settings, hideOnDesktop: e.target.checked })}
                    className="h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded"
                  />
                </div>
              </div>
              <div className="space-y-4 pt-4 border-t">
                <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider">Анимация</h3>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Появление</label>
                  <select
                    value={selectedBlock.settings?.animation || 'none'}
                    onChange={(e) => updateBlock(selectedBlock.id, {}, {}, { ...selectedBlock.settings, animation: e.target.value as any })}
                    className="w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500"
                  >
                    <option value="none">Без анимации</option>
                    <option value="fade">Fade (Проявление)</option>
                    <option value="slide-up">Slide Up (Появление снизу)</option>
                    <option value="zoom-in">Zoom In (Увеличение)</option>
                  </select>
                </div>
              </div>
              <div className="space-y-4 pt-4 border-t">
                <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider">Shape Dividers</h3>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Верхний край (SVG URL или код)</label>
                  <input
                    type="text"
                    placeholder="<svg>...</svg>"
                    value={selectedBlock.settings?.shapeDividerTop || ''}
                    onChange={(e) => updateBlock(selectedBlock.id, {}, {}, { ...selectedBlock.settings, shapeDividerTop: e.target.value })}
                    className="w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Нижний край (SVG URL или код)</label>
                  <input
                    type="text"
                    placeholder="<svg>...</svg>"
                    value={selectedBlock.settings?.shapeDividerBottom || ''}
                    onChange={(e) => updateBlock(selectedBlock.id, {}, {}, { ...selectedBlock.settings, shapeDividerBottom: e.target.value })}
                    className="w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>
              </div>
              <div className="space-y-4 pt-4 border-t">
                <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider">Стили</h3>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Цвет фона</label>
                  <input
                    type="color"
                    value={selectedBlock.styles?.backgroundColor || '#ffffff'}
                    onChange={(e) => updateBlock(selectedBlock.id, { styles: { ...selectedBlock.styles, backgroundColor: e.target.value } })}
                    className="w-full h-8 border border-gray-300 rounded-md"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Градиент (CSS)</label>
                  <input
                    type="text"
                    placeholder="linear-gradient(90deg, #ff0000, #0000ff)"
                    value={selectedBlock.styles?.gradient || ''}
                    onChange={(e) => updateBlock(selectedBlock.id, { styles: { ...selectedBlock.styles, gradient: e.target.value } })}
                    className="w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Цвет текста</label>
                  <input
                    type="color"
                    value={selectedBlock.styles?.color || '#000000'}
                    onChange={(e) => updateBlock(selectedBlock.id, { styles: { ...selectedBlock.styles, color: e.target.value } })}
                    className="w-full h-8 border border-gray-300 rounded-md"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Отступы внутри (padding)</label>
                  <input
                    type="text"
                    placeholder="1rem 2rem"
                    value={selectedBlock.styles?.padding || ''}
                    onChange={(e) => updateBlock(selectedBlock.id, { styles: { ...selectedBlock.styles, padding: e.target.value } })}
                    className="w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Отступы снаружи (margin)</label>
                  <input
                    type="text"
                    placeholder="1rem auto"
                    value={selectedBlock.styles?.margin || ''}
                    onChange={(e) => updateBlock(selectedBlock.id, { styles: { ...selectedBlock.styles, margin: e.target.value } })}
                    className="w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Скругление (border-radius)</label>
                  <input
                    type="text"
                    placeholder="8px"
                    value={selectedBlock.styles?.borderRadius || ''}
                    onChange={(e) => updateBlock(selectedBlock.id, { styles: { ...selectedBlock.styles, borderRadius: e.target.value } })}
                    className="w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Тень (box-shadow)</label>
                  <input
                    type="text"
                    placeholder="0 4px 6px rgba(0,0,0,0.1)"
                    value={selectedBlock.styles?.boxShadow || ''}
                    onChange={(e) => updateBlock(selectedBlock.id, { styles: { ...selectedBlock.styles, boxShadow: e.target.value } })}
                    className="w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>
              </div>
            </div>
          ) : (
            <div className="text-gray-400 text-sm text-center mt-10">
              Выберите блок на холсте для настройки
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// Утилита для рендера блока на холсте
// eslint-disable-next-line unused-imports/no-unused-vars
function BlockRenderer({ block }: { block: EditorBlock }) {
  switch (block.type) {
    case "Hero":
      return (
        <div className="py-20 px-8 text-center bg-gray-50">
          <h1 className="text-4xl font-bold mb-4">{block.content.title}</h1>
          <p className="text-xl text-gray-600">{block.content.subtitle}</p>
        </div>
      );
    case "Heading":
      return <h2 className="text-2xl font-bold p-4">{block.content.text}</h2>;
    case "Paragraph":
      return <p className="text-base text-gray-700 p-4">{block.content.text}</p>;
    case "Image":
      return (
        <div className="p-4">
          <img 
            src={block.content.src || "https://via.placeholder.com/800x400"} 
            alt={block.content.alt}
            className="w-full h-auto object-cover rounded-md"
          />
        </div>
      );
    case "ProductGrid":
      return (
        <div className="py-12 px-8 bg-white border-2 border-dashed border-gray-200 m-4 rounded-xl text-center">
          <h3 className="text-2xl font-bold mb-4">{block.content.title}</h3>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 opacity-50">
            {[...Array(Number(block.content.limit) || 4)].map((_, i) => (
              <div key={i} className="bg-gray-100 h-48 rounded-lg animate-pulse"></div>
            ))}
          </div>
          <p className="mt-4 text-sm text-gray-400">
            Здесь будет выведена реальная сетка товаров на витрине магазина.
          </p>
        </div>
      );
    case "BannerSlider":
      return (
        <div className="h-64 bg-gradient-to-r from-blue-500 to-purple-600 flex items-center justify-center border-2 border-dashed border-blue-300 m-4 rounded-xl">
          <div className="text-white text-center">
            <svg className="w-12 h-12 mx-auto mb-2 opacity-50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
            <p className="font-medium">Баннер-карусель</p>
            <p className="text-sm opacity-75">Баннеры подтягиваются из раздела "Баннеры"</p>
          </div>
        </div>
      );
    case "Accordion":
      return (
        <div className="p-4 space-y-2">
          <h3 className="text-xl font-bold mb-4">{block.content.title}</h3>
          {(block.content.items as { question: string; answer: string }[]).map((item, i) => (
            <div key={i} className="border rounded p-3 bg-gray-50">
              <div className="font-medium">{item.question}</div>
              <div className="text-sm text-gray-600 mt-1">{item.answer}</div>
            </div>
          ))}
        </div>
      );
    case "DropdownMenu":
      return (
        <div className="p-4 inline-block">
          <div className="bg-blue-600 text-white px-4 py-2 rounded cursor-pointer">{block.content.label} ▾</div>
          {/* Simulated dropdown */}
          <div className="mt-1 border rounded shadow-md bg-white opacity-50 absolute pointer-events-none">
            {(block.content.items as { label: string; href: string }[]).map((item, i) => (
              <div key={i} className="px-4 py-2 hover:bg-gray-100 text-sm border-b last:border-0">{item.label}</div>
            ))}
          </div>
        </div>
      );
    case "PopupBanner":
      return (
        <div className="p-8 border-2 border-dashed border-purple-300 bg-purple-50 rounded-xl relative">
          <div className="absolute top-2 right-2 text-xs bg-purple-200 text-purple-800 px-2 py-1 rounded">Popup (Preview)</div>
          <h3 className="text-2xl font-bold text-purple-900">{block.content.title}</h3>
          <p className="mt-2 text-purple-800">{block.content.message}</p>
          <button className="mt-4 bg-purple-600 text-white px-6 py-2 rounded-full">{block.content.buttonText}</button>
          <div className="mt-4 text-xs text-gray-500">
            Trigger: {block.settings?.trigger || 'onLoad'} {block.settings?.delayInSeconds ? `(${block.settings.delayInSeconds}s)` : ''}
          </div>
        </div>
      );
    case "GridContainer":
      return (
        <div 
          className="p-4 bg-gray-50"
          style={{
            display: 'grid',
            gridTemplateColumns: `repeat(${block.content.columns || 12}, 1fr)`,
            gap: block.content.gap || '16px'
          }}
        >
          // eslint-disable-next-line unused-imports/no-unused-vars
          {(block.content.items as any[]).map((item, i) => (
            <div 
              key={item.id} 
              className="border-2 border-dashed border-gray-300 bg-white min-h-[100px] flex flex-col items-center justify-center p-2 text-sm text-gray-400"
              style={{
                gridColumn: `span ${item.colSpan || 4}`,
                gridRow: `span ${item.rowSpan || 1}`
              }}
            >
              Ячейка сетки (col: {item.colSpan}, row: {item.rowSpan})
            </div>
          ))}
        </div>
      );
    default:
      return <div>Unknown Block</div>;
  }
}

// Утилита для дефолтного контента
