"use client";

import { useState, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { toast } from "sonner";
import { Plus, Edit, Trash, FolderTree, X, Upload, Image as ImageIcon, Loader2 } from "lucide-react";
import { createCategory, updateCategory, deleteCategory } from "@/actions/category";

interface Category {
  id: string;
  name: string;
  slug: string | null;
  parentId: string | null;
  isGlobal: boolean;
  imageUrl?: string | null;
  createdAt: Date;
}

interface CategoriesClientProps {
  initialData: Category[];
  storeId: string;
}

export function CategoriesClient({ initialData, storeId }: CategoriesClientProps) {
  const [categories, setCategories] = useState<Category[]>(initialData);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [name, setName] = useState("");
  const [parentId, setParentId] = useState<string>("");
  const [imageUrl, setImageUrl] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Отримуємо всі категорії, які можуть бути батьківськими (усі окрім поточної)
  const parentCategories = categories.filter(
    (cat) => cat.id !== editingCategory?.id
  );

  const openAddDialog = () => {
    setEditingCategory(null);
    setName("");
    setParentId("none");
    setImageUrl("");
    setIsDialogOpen(true);
  };

  const openEditDialog = (category: Category) => {
    setEditingCategory(category);
    setName(category.name);
    setParentId(category.parentId || "none");
    setImageUrl(category.imageUrl || "");
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingCategory(null);
    setName("");
    setParentId("none");
    setImageUrl("");
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith("image/")) {
      toast.error("Будь ласка, виберіть зображення");
      return;
    }

    setIsUploading(true);
    try {
      const formData = new FormData();
      formData.append("file", file);

      const res = await fetch(`/api/upload?storeId=${storeId}`, {
        method: "POST",
        body: formData,
      });

      const data = await res.json();

      if (data.url) {
        setImageUrl(data.url);
        toast.success("Зображення завантажено");
      } else {
        toast.error(data.error || "Помилка завантаження");
      }
    } catch (error) {
      toast.error("Помилка завантаження зображення");
      console.error(error);
    } finally {
      setIsUploading(false);
    }
  };

  const handleSubmit = async () => {
    if (!name.trim()) {
      toast.error("Введіть назву категорії");
      return;
    }

    setIsLoading(true);

    try {
      const categoryData = {
        name: name.trim(),
        slug: name
          .trim()
          .toLowerCase()
          .replace(/[^\w\s-]/g, "")
          .replace(/\s+/g, "-")
          .replace(/-+/g, "-")
          .trim(),
        parentId: parentId || null,
        imageUrl: imageUrl || undefined,
      };

      let result;
      if (editingCategory) {
        result = await updateCategory(storeId, editingCategory.id, categoryData);
      } else {
        result = await createCategory(storeId, categoryData);
      }

      if (result?.error) {
        toast.error(result.error);
      } else if (result?.success) {
        toast.success(result.success);
        // Оновлюємо список категорій
        if (result.category) {
          if (editingCategory) {
            setCategories(
              categories.map((cat) =>
                cat.id === editingCategory.id
                  ? { ...cat, ...result.category }
                  : cat
              )
            );
          } else {
            setCategories([...categories, result.category]);
          }
        }
        handleCloseDialog();
      }
    // eslint-disable-next-line unused-imports/no-unused-vars
    } catch (error) {
      toast.error("Сталася помилка при збереженні категорії");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (
      !confirm("Ви впевнені, що хочете видалити цю категорію?")
    ) {
      return;
    }

    const result = await deleteCategory(storeId, id);

    if (result?.error) {
      toast.error(result.error);
    } else if (result?.success) {
      toast.success(result.success);
      setCategories(categories.filter((cat) => cat.id !== id));
    }
  };

  // Обчислюємо відступ для візуалізації ієрархії
  const getIndentation = (category: Category): number => {
    if (!category.parentId) return 0;
    const parent = categories.find((c) => c.id === category.parentId);
    if (!parent) return 0;
    return 1 + getIndentation(parent);
  };

  // Сортуємо категорії: спочатку без батьків, потім в порядку вкладеності
  const sortedCategories = [...categories].sort((a, b) => {
    const aIndent = getIndentation(a);
    const bIndent = getIndentation(b);
    if (aIndent !== bIndent) return aIndent - bIndent;
    return a.name.localeCompare(b.name);
  });

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <div className="flex items-center gap-2">
          <FolderTree className="w-6 h-6 text-primary" />
          <h3 className="text-lg font-medium">Категорії магазину</h3>
        </div>
        <Button onClick={openAddDialog}>
          <Plus className="w-4 h-4 mr-2" /> Додати категорію
        </Button>
      </div>

      <div className="bg-white border rounded-xl shadow-sm overflow-hidden">
        <table className="w-full text-sm text-left">
          <thead className="bg-gray-50 text-gray-500">
            <tr>
              <th className="px-6 py-3 font-medium">Назва</th>
              <th className="px-6 py-3 font-medium">URL (Slug)</th>
              <th className="px-6 py-3 font-medium">Батьківська категорія</th>
              <th className="px-6 py-3 font-medium text-right">Дії</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {sortedCategories.map((cat) => {
              const indent = getIndentation(cat);
              const parentCategory = categories.find(
                (c) => c.id === cat.parentId
              );
              return (
                <tr key={cat.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 font-medium">
                    <div className="flex items-center gap-2">
                      {cat.imageUrl && (
                        <div className="w-8 h-8 rounded-md overflow-hidden bg-gray-100 flex-shrink-0">
                          <img
                            src={cat.imageUrl}
                            alt={cat.name}
                            className="w-full h-full object-cover"
                          />
                        </div>
                      )}
                      {indent > 0 && (
                        <span className="text-gray-400">
                          {"— ".repeat(indent)}
                        </span>
                      )}
                      {cat.name}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-gray-500">{cat.slug}</td>
                  <td className="px-6 py-4 text-gray-500">
                    {parentCategory ? (
                      <span className="inline-flex items-center gap-1">
                        <FolderTree className="w-3 h-3" />
                        {parentCategory.name}
                      </span>
                    ) : (
                      <span className="text-gray-400">—</span>
                    )}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => openEditDialog(cat)}
                      >
                        <Edit className="w-4 h-4 text-blue-500" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => handleDelete(cat.id)}
                      >
                        <Trash className="w-4 h-4 text-red-500" />
                      </Button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Діалогове вікно для додавання/редагування */}
      <Dialog open={isDialogOpen} onOpenChange={handleCloseDialog}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle>
              {editingCategory ? "Редагувати категорію" : "Додати категорію"}
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="name">Назва категорії *</Label>
              <Input
                id="name"
                placeholder="Наприклад: Електроніка"
                value={name}
                onChange={(e) => setName(e.target.value)}
                disabled={isLoading}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="image">Зображення категорії</Label>
              <div className="flex items-center gap-4">
                {imageUrl ? (
                  <div className="relative w-24 h-24 rounded-lg overflow-hidden border border-gray-200 bg-gray-50">
                    <img
                      src={imageUrl}
                      alt="Category"
                      className="w-full h-full object-cover"
                    />
                    <button
                      type="button"
                      onClick={() => setImageUrl("")}
                      className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded-full hover:bg-red-600"
                    >
                      <X className="w-3 h-3" />
                    </button>
                  </div>
                ) : (
                  <div
                    className="w-24 h-24 border-2 border-dashed border-gray-300 rounded-lg flex items-center justify-center cursor-pointer hover:border-primary hover:bg-gray-50 transition-colors"
                    onClick={() => fileInputRef.current?.click()}
                  >
                    <div className="text-center">
                      <ImageIcon className="w-8 h-8 text-gray-400 mx-auto mb-1" />
                      <p className="text-xs text-gray-500">Натисніть</p>
                    </div>
                  </div>
                )}
                <div className="flex-1">
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept="image/*"
                    onChange={handleFileUpload}
                    className="hidden"
                  />
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => fileInputRef.current?.click()}
                    disabled={isUploading || isLoading}
                    className="w-full"
                  >
                    {isUploading ? (
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    ) : (
                      <Upload className="w-4 h-4 mr-2" />
                    )}
                    {isUploading ? "Завантаження..." : "Завантажити зображення"}
                  </Button>
                  <p className="text-xs text-gray-500 mt-1">
                    Підтримуються формати: JPG, PNG, WebP
                  </p>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="parent">Батьківська категорія</Label>
              <Select
                value={parentId || "none"}
                onValueChange={(val) => setParentId(val === "none" ? "" : val)}
                disabled={isLoading}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Оберіть батьківську категорію (необов'язково)" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="none">Немає (коренева категорія)</SelectItem>
                  {parentCategories.map((cat) => (
                    <SelectItem key={cat.id} value={cat.id}>
                      {cat.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <p className="text-xs text-gray-500">
                Виберіть батьківську категорію для створення вкладеної категорії
              </p>
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={handleCloseDialog} disabled={isLoading}>
              <X className="w-4 h-4 mr-2" /> Скасувати
            </Button>
            <Button onClick={handleSubmit} disabled={isLoading || isUploading}>
              {isLoading ? "Збереження..." : "Зберегти"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

