'use client';

import { useState, useEffect } from 'react';
import { getCustomerGroups, saveCustomerGroup, deleteCustomerGroup } from '@/actions/customer-groups';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Plus, Pencil, Trash2, Users } from 'lucide-react';

interface CustomerGroup {
  id: string;
  name: string;
  discountPercentage: number;
  userCount: number;
  priceCount: number;
}

interface CustomerGroupsClientProps {
  storeId: string;
  storeName: string;
}

export function CustomerGroupsClient({ storeId, storeName }: CustomerGroupsClientProps) {
  const [groups, setGroups] = useState<CustomerGroup[]>([]);
  const [loading, setLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingGroup, setEditingGroup] = useState<CustomerGroup | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    discountPercentage: 0,
    description: '',
  });

  const loadGroups = async () => {
    setLoading(true);
    const result = await getCustomerGroups(storeId);
    if (result.success) {
      setGroups(result.data);
    }
    setLoading(false);
  };

  useEffect(() => {
    loadGroups();
  }, [storeId]);

  const handleOpenChange = (open: boolean) => {
    setIsDialogOpen(open);
    if (!open) {
      setEditingGroup(null);
      setFormData({ name: '', discountPercentage: 0, description: '' });
    }
  };

  const handleEdit = (group: CustomerGroup) => {
    setEditingGroup(group);
    setFormData({
      name: group.name,
      discountPercentage: group.discountPercentage,
      description: '',
    });
    setIsDialogOpen(true);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();

    const result = await saveCustomerGroup(storeId, {
      id: editingGroup?.id,
      name: formData.name,
      discountPercentage: formData.discountPercentage,
    });

    if (result.success) {
      loadGroups();
      handleOpenChange(false);
    } else {
      alert(result.error || 'Помилка збереження');
    }
  };

  const handleDelete = async (groupId: string) => {
    if (!confirm('Ви впевнені, що хочете видалити цю групу?')) return;

    const result = await deleteCustomerGroup(groupId, storeId);
    if (result.success) {
      loadGroups();
    } else {
      alert(result.error || 'Помилка видалення');
    }
  };

  return (
    <div className="container mx-auto p-6">
      <div className="mb-6">
        <h1 className="text-3xl font-bold">Групи клієнтів</h1>
        <p className="text-gray-500">Керування групами клієнтів для магазину "{storeName}"</p>
      </div>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle>Список груп</CardTitle>
            <CardDescription>
              Створіть групи клієнтів для застосування знижок до певних категорій покупців
            </CardDescription>
          </div>
          <Dialog open={isDialogOpen} onOpenChange={handleOpenChange}>
            <DialogTrigger asChild>
              <Button onClick={() => {
                setEditingGroup(null);
                setFormData({ name: '', discountPercentage: 0, description: '' });
              }}>
                <Plus className="w-4 h-4 mr-2" />
                Створити групу
              </Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>
                  {editingGroup ? 'Редагувати групу' : 'Нова група клієнтів'}
                </DialogTitle>
              </DialogHeader>
              <form onSubmit={handleSave} className="space-y-4">
                <div>
                  <Label htmlFor="name">Назва групи</Label>
                  <Input
                    id="name"
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    placeholder="Наприклад: Оптові покупці"
                    required
                  />
                </div>
                <div>
                  <Label htmlFor="discount">Відсоток знижки (%)</Label>
                  <Input
                    id="discount"
                    type="number"
                    min="0"
                    max="100"
                    value={formData.discountPercentage}
                    onChange={(e) => setFormData({ ...formData, discountPercentage: Number(e.target.value) })}
                    required
                  />
                </div>
                <div className="flex justify-end gap-2">
                  <Button type="button" variant="outline" onClick={() => handleOpenChange(false)}>
                    Скасувати
                  </Button>
                  <Button type="submit">
                    {editingGroup ? 'Зберегти' : 'Створити'}
                  </Button>
                </div>
              </form>
            </DialogContent>
          </Dialog>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="text-center py-8 text-gray-500">Завантаження...</div>
          ) : groups.length === 0 ? (
            <div className="text-center py-8 text-gray-500">
              Немає жодної групи клієнтів. Створіть першу групу.
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Назва</TableHead>
                  <TableHead>Знижка</TableHead>
                  <TableHead>Кількість користувачів</TableHead>
                  <TableHead>С1іни продуктів</TableHead>
                  <TableHead className="text-right">Дії</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {groups.map((group) => (
                  <TableRow key={group.id}>
                    <TableCell className="font-medium">{group.name}</TableCell>
                    <TableCell>
                      <Badge variant={group.discountPercentage > 0 ? 'default' : 'secondary'}>
                        {group.discountPercentage}%
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-1">
                        <Users className="w-4 h-4 text-gray-500" />
                        {group.userCount}
                      </div>
                    </TableCell>
                    <TableCell>{group.priceCount}</TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleEdit(group)}
                        >
                          <Pencil className="w-4 h-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleDelete(group.id)}
                        >
                          <Trash2 className="w-4 h-4 text-red-500" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState, useTransition } from "react";
import { useRouter } from "next/navigation";
import {
  createWarehouse,
  addStockMovement,
  getWarehouseStock,
  getStockMovements,
} from "@/actions/inventory";
import { toast } from "sonner";
import {
  Warehouse,
  Package,
  Plus,
  TrendingUp,
  TrendingDown,
  ArrowLeftRight,
  AlertTriangle,
  BarChart3,
  RefreshCw,
} from "lucide-react";

// ─── Типы ─────────────────────────────────────────────────────────────────────

interface WarehouseItem {
  id: string;
  name: string;
  address: string | null;
  isDefault: boolean;
  _count: { stock: number };
}

interface ProductItem {
  id: string;
  name: string;
  imageUrl: string | null;
  stock: number;
}

interface InventoryStats {
  warehousesCount: number;
  totalProducts: number;
  totalQuantity: number;
  totalAvailable: number;
  totalReserved: number;
  lowStockCount: number;
}

interface InventoryClientProps {
  storeId: string;
  warehouses: WarehouseItem[];
  products: ProductItem[];
  stats: InventoryStats;
  selectedWarehouseId?: string;
  abcAnalysis?: { id: string; name: string; revenue: number; category: "A" | "B" | "C" }[];
}

// ─── Модальное окно создания склада ───────────────────────────────────────────

function CreateWarehouseModal({
  storeId,
  onClose,
  onCreated,
}: {
  storeId: string;
  onClose: () => void;
  onCreated: () => void;
}) {
  const [name, setName] = useState("");
  const [address, setAddress] = useState("");
  const [isDefault, setIsDefault] = useState(false);
  const [isPending, startTransition] = useTransition();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    startTransition(async () => {
      const result = await createWarehouse({ storeId, name, address, isDefault });
      if (result.success) {
        toast.success("Склад создан");
        onCreated();
        onClose();
      } else {
        toast.error(result.error ?? "Ошибка создания склада");
      }
    });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
      <div className="bg-white dark:bg-slate-800 rounded-xl p-6 w-full max-w-md shadow-xl">
        <h2 className="text-lg font-bold text-slate-900 dark:text-white mb-4">Создать склад</h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Название *
            </label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
              placeholder="Главный склад"
              className="w-full border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Адрес
            </label>
            <input
              type="text"
              value={address}
              onChange={(e) => setAddress(e.target.value)}
              placeholder="ул. Примерная, 1"
              className="w-full border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <label className="flex items-center gap-3 cursor-pointer">
            <input
              type="checkbox"
              checked={isDefault}
              onChange={(e) => setIsDefault(e.target.checked)}
              className="w-4 h-4 rounded border-slate-300 text-blue-600"
            />
            <span className="text-sm text-slate-700 dark:text-slate-300">Склад по умолчанию</span>
          </label>
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-sm text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg"
            >
              Отмена
            </button>
            <button
              type="submit"
              disabled={isPending}
              className="px-4 py-2 text-sm bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-medium rounded-lg"
            >
              {isPending ? "Создание..." : "Создать"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

// ─── Модальное окно движения стока ────────────────────────────────────────────

function StockMovementModal({
  warehouseId,
  products,
  onClose,
  onDone,
}: {
  warehouseId: string;
  products: ProductItem[];
  onClose: () => void;
  onDone: () => void;
}) {
  const [productId, setProductId] = useState(products[0]?.id ?? "");
  const [type, setType] = useState<"RECEIPT" | "SALE" | "RETURN" | "ADJUSTMENT" | "TRANSFER">("RECEIPT");
  const [quantity, setQuantity] = useState("1");
  const [reason, setReason] = useState("");
  const [isPending, startTransition] = useTransition();

  const MOVEMENT_TYPES = [
    { value: "RECEIPT", label: "Поступление", icon: TrendingUp, color: "text-green-600" },
    { value: "SALE", label: "Продажа", icon: TrendingDown, color: "text-red-600" },
    { value: "RETURN", label: "Возврат", icon: RefreshCw, color: "text-blue-600" },
    { value: "ADJUSTMENT", label: "Корректировка", icon: ArrowLeftRight, color: "text-purple-600" },
    { value: "TRANSFER", label: "Перемещение", icon: ArrowLeftRight, color: "text-orange-600" },
  ];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    startTransition(async () => {
      const result = await addStockMovement({
        warehouseId,
        productId,
        type,
        quantity: parseInt(quantity, 10),
        reason,
      });
      if (result.success) {
        toast.success("Движение товара записано");
        onDone();
        onClose();
      } else {
        toast.error(result.error ?? "Ошибка");
      }
    });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
      <div className="bg-white dark:bg-slate-800 rounded-xl p-6 w-full max-w-md shadow-xl">
        <h2 className="text-lg font-bold text-slate-900 dark:text-white mb-4">
          Добавить движение товара
        </h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Товар *
            </label>
            <select
              value={productId}
              onChange={(e) => setProductId(e.target.value)}
              required
              className="w-full border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {products.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.name} (остаток: {p.stock})
                </option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Тип движения *
            </label>
            <div className="grid grid-cols-2 gap-2">
              {MOVEMENT_TYPES.map((mt) => (
                <button
                  key={mt.value}
                  type="button"
                  onClick={() => setType(mt.value as typeof type)}
                  className={`flex items-center gap-2 px-3 py-2 text-sm font-medium rounded-lg border transition-colors ${
                    type === mt.value
                      ? "border-blue-500 bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300"
                      : "border-slate-200 dark:border-slate-600 text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700"
                  }`}
                >
                  <mt.icon className={`w-4 h-4 ${mt.color}`} />
                  {mt.label}
                </button>
              ))}
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Количество *
            </label>
            <input
              type="number"
              min="1"
              value={quantity}
              onChange={(e) => setQuantity(e.target.value)}
              required
              className="w-full border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
              Причина / Комментарий
            </label>
            <input
              type="text"
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder="Необязательно"
              className="w-full border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-sm text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg"
            >
              Отмена
            </button>
            <button
              type="submit"
              disabled={isPending}
              className="px-4 py-2 text-sm bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-medium rounded-lg"
            >
              {isPending ? "Запись..." : "Записать"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

// ─── Основной компонент ────────────────────────────────────────────────────────

export function InventoryClient({
  storeId,
  warehouses,
  products,
  stats,
  selectedWarehouseId,
  abcAnalysis = [],
}: InventoryClientProps) {
  const router = useRouter();
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [showMovementModal, setShowMovementModal] = useState(false);
  const [activeWarehouseId, setActiveWarehouseId] = useState(selectedWarehouseId);
  const [stockList, setStockList] = useState<
    { id: string; quantity: number; available: number; reserved: number; product: ProductItem }[]
  >([]);
  const [movements, setMovements] = useState<
    {
      id: string;
      type: string;
      quantity: number;
      reason: string | null;
      createdAt: string;
      product: ProductItem;
    }[]
  >([]);
  const [activeTab, setActiveTab] = useState<"stock" | "movements" | "abc">("stock");
  const [loading, setLoading] = useState(false);

  const loadWarehouseData = async (warehouseId: string) => {
    setLoading(true);
    const [stockData, movementsData] = await Promise.all([
      getWarehouseStock(warehouseId),
      getStockMovements(warehouseId),
    ]);
    setStockList(stockData as typeof stockList);
    setMovements(movementsData as typeof movements);
    setLoading(false);
  };

  const handleWarehouseSelect = (warehouseId: string) => {
    setActiveWarehouseId(warehouseId);
    loadWarehouseData(warehouseId);
    router.push(`/dashboard/${storeId}/inventory?warehouseId=${warehouseId}`);
  };

  const MOVEMENT_ICONS: Record<string, React.ElementType> = {
    RECEIPT: TrendingUp,
    SALE: TrendingDown,
    RETURN: RefreshCw,
    ADJUSTMENT: ArrowLeftRight,
    TRANSFER: ArrowLeftRight,
  };

  const MOVEMENT_LABELS: Record<string, string> = {
    RECEIPT: "Поступление",
    SALE: "Продажа",
    RETURN: "Возврат",
    ADJUSTMENT: "Корректировка",
    TRANSFER: "Перемещение",
  };

  const MOVEMENT_COLORS: Record<string, string> = {
    RECEIPT: "text-green-600",
    SALE: "text-red-600",
    RETURN: "text-blue-600",
    ADJUSTMENT: "text-purple-600",
    TRANSFER: "text-orange-600",
  };

  return (
    <div className="space-y-6">
      {/* Заголовок */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-900 dark:text-white">
            Управление складом
          </h1>
          <p className="text-slate-500 dark:text-slate-400 mt-1">
            Остатки товаров, движения и аналитика по складам
          </p>
        </div>
        <button
          onClick={() => setShowCreateModal(true)}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium px-4 py-2 rounded-lg transition-colors"
        >
          <Plus className="w-4 h-4" />
          Добавить склад
        </button>
      </div>

      {/* Статистика */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
        {[
          { label: "Складов", value: stats.warehousesCount, icon: Warehouse, color: "bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400" },
          { label: "Позиций", value: stats.totalProducts, icon: Package, color: "bg-green-100 text-green-600 dark:bg-green-900/30 dark:text-green-400" },
          { label: "Всего единиц", value: stats.totalQuantity, icon: BarChart3, color: "bg-purple-100 text-purple-600 dark:bg-purple-900/30 dark:text-purple-400" },
          { label: "Доступно", value: stats.totalAvailable, icon: TrendingUp, color: "bg-teal-100 text-teal-600 dark:bg-teal-900/30 dark:text-teal-400" },
          { label: "Зарезервировано", value: stats.totalReserved, icon: ArrowLeftRight, color: "bg-orange-100 text-orange-600 dark:bg-orange-900/30 dark:text-orange-400" },
          { label: "Мало в наличии", value: stats.lowStockCount, icon: AlertTriangle, color: "bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400" },
        ].map((item) => (
          <div
            key={item.label}
            className="bg-white dark:bg-slate-800 rounded-xl p-4 border border-slate-200 dark:border-slate-700"
          >
            <div className="flex items-center gap-3">
              <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${item.color}`}>
                <item.icon className="w-5 h-5" />
              </div>
              <div>
                <p className="text-xs text-slate-500 dark:text-slate-400">{item.label}</p>
                <p className="text-xl font-bold text-slate-900 dark:text-white">{item.value}</p>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-12 gap-6">
        {/* Список складов (боковая панель) */}
        <div className="col-span-12 lg:col-span-3 space-y-2">
          <h2 className="text-sm font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider px-1">
            Склады
          </h2>
          {warehouses.length === 0 ? (
            <div className="text-center py-8 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700">
              <Warehouse className="w-8 h-8 text-slate-300 dark:text-slate-600 mx-auto mb-2" />
              <p className="text-sm text-slate-500 dark:text-slate-400">Нет складов</p>
            </div>
          ) : (
            warehouses.map((wh) => (
              <button
                key={wh.id}
                onClick={() => handleWarehouseSelect(wh.id)}
                className={`w-full text-left p-4 rounded-xl border transition-all ${
                  activeWarehouseId === wh.id
                    ? "border-blue-500 bg-blue-50 dark:bg-blue-900/20"
                    : "border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 hover:border-slate-300 dark:hover:border-slate-600"
                }`}
              >
                <div className="flex items-center gap-3">
                  <div className={`w-9 h-9 rounded-lg flex items-center justify-center ${activeWarehouseId === wh.id ? "bg-blue-600" : "bg-slate-100 dark:bg-slate-700"}`}>
                    <Warehouse className={`w-5 h-5 ${activeWarehouseId === wh.id ? "text-white" : "text-slate-500"}`} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <span className="font-medium text-slate-900 dark:text-white text-sm truncate">
                        {wh.name}
                      </span>
                      {wh.isDefault && (
                        <span className="text-xs bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 px-1.5 py-0.5 rounded">
                          По умол.
                        </span>
                      )}
                    </div>
                    <p className="text-xs text-slate-500 dark:text-slate-400">
                      {wh._count.stock} позиций
                    </p>
                  </div>
                </div>
              </button>
            ))
          )}
        </div>

        {/* Основная область */}
        <div className="col-span-12 lg:col-span-9">
          {!activeWarehouseId ? (
            <div className="text-center py-20 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700">
              <Warehouse className="w-12 h-12 text-slate-300 dark:text-slate-600 mx-auto mb-3" />
              <p className="text-slate-500 dark:text-slate-400 font-medium">Выберите склад</p>
              <p className="text-sm text-slate-400 dark:text-slate-500 mt-1">
                Или создайте новый склад
              </p>
            </div>
          ) : (
            <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700">
              {/* Табы */}
              <div className="flex items-center justify-between p-4 border-b border-slate-200 dark:border-slate-700">
                <div className="flex gap-1">
                  {(["stock", "movements", "abc"] as const).map((tab) => (
                    <button
                      key={tab}
                      onClick={() => setActiveTab(tab)}
                      className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors ${
                        activeTab === tab
                          ? "bg-slate-100 dark:bg-slate-700 text-slate-900 dark:text-white"
                          : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200"
                      }`}
                    >
                      {tab === "stock" ? "Остатки" : tab === "abc" ? "ABC-Анализ" : "История движений"}
                    </button>
                  ))}
                </div>
                <button
                  onClick={() => setShowMovementModal(true)}
                  className="flex items-center gap-2 bg-slate-800 dark:bg-slate-600 hover:bg-slate-700 text-white text-sm font-medium px-3 py-2 rounded-lg transition-colors"
                >
                  <Plus className="w-4 h-4" />
                  Движение
                </button>
              </div>

              {loading ? (
                <div className="text-center py-12">
                  <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto" />
                </div>
              ) : activeTab === "stock" ? (
                <div>
                  {stockList.length === 0 ? (
                    <div className="text-center py-12">
                      <Package className="w-10 h-10 text-slate-300 dark:text-slate-600 mx-auto mb-2" />
                      <p className="text-slate-500 dark:text-slate-400">
                        Остатки не найдены. Добавьте движение товара.
                      </p>
                    </div>
                  ) : (
                    <div className="overflow-x-auto">
                    <table className="w-full">
                      <thead className="bg-slate-50 dark:bg-slate-700/50">
                        <tr>
