"use client";

import { useState, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import { OrderKanbanBoard } from "./kanban-board";
import { OrdersTable } from "./orders-table";
import { Button } from "@/components/ui/button";
import { LayoutList, LayoutGrid } from "lucide-react";
import { OrderWithItems } from "./types";

interface OrdersClientProps {
  initialOrders: OrderWithItems[];
  storeId: string;
  totalPages: number;
  currentPage: number;
}

export function OrdersClient({
  initialOrders,
  storeId,
  // eslint-disable-next-line unused-imports/no-unused-vars
  totalPages,
  // eslint-disable-next-line unused-imports/no-unused-vars
  currentPage: initialPage,
}: OrdersClientProps) {
  const [view, setView] = useState<"table" | "kanban">("table");
  const [isMounted, setIsMounted] = useState(false);
  const router = useRouter();

  useEffect(() => {
    setIsMounted(true);
    const savedView = localStorage.getItem("orders-view") as "table" | "kanban";
    if (savedView && ["table", "kanban"].includes(savedView)) {
      setView(savedView);
    }
  }, []);

  const toggleView = () => {
    const newView = view === "table" ? "kanban" : "table";
    setView(newView);
    localStorage.setItem("orders-view", newView);
  };

  const handleViewDetails = useCallback((orderId: string) => {
    router.push(`/dashboard/${storeId}/orders/${orderId}`);
  }, [storeId, router]);

  if (!isMounted) {
    return (
      <div className="flex justify-center items-center h-full min-h-screen">
        <div className="text-gray-500">Завантаження...</div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full min-h-screen">
      <div className="flex justify-end items-center mb-4">
        <div className="flex items-center border border-gray-200 rounded-lg overflow-hidden">
          <Button
            variant={view === "table" ? "default" : "ghost"}
            size="icon"
            onClick={toggleView}
            className="rounded-none"
            title="Таблиця"
          >
            <LayoutList className="h-4 w-4" />
          </Button>
          <Button
            variant={view === "kanban" ? "default" : "ghost"}
            size="icon"
            onClick={toggleView}
            className="rounded-none border-l border-gray-200"
            title="Канбан"
          >
            <LayoutGrid className="h-4 w-4" />
          </Button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden">
        {view === "table" ? (
          <OrdersTable
            orders={initialOrders}
            storeId={storeId}
            onViewDetails={handleViewDetails}
          />
        ) : (
          <OrderKanbanBoard orders={initialOrders} storeId={storeId} />
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useForm, useFieldArray } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { productSchema, ProductInput } from "@/lib/validations/product";
import { createProduct, updateProduct } from "@/actions/product";
import { Category } from "@prisma/client";
import { Button } from "@/components/ui/button";
import { Loader2, Plus, Trash } from "lucide-react";
import { ProductImageUploader, ImageItem } from "@/components/dashboard/product-image-uploader";
import { ProductTranslationTabs, TranslationsMap } from "@/components/dashboard/product-translation-tabs";
import { saveProductTranslation } from "@/actions/translations";
import { AIWritingToolbar } from "@/components/dashboard/ai-writing-toolbar";
import { SEOGenerator } from "@/components/dashboard/seo-generator";

interface ProductFormProps {
  initialData: any | null;
  categories: Category[];
  storeId: string;
}

// Функція для візуалізації ієрархії категорій з відступами
const flattenCategories = (categories: Category[], parentId: string | null = null, level: number = 0): { id: string; name: string; level: number }[] => {
  const result: { id: string; name: string; level: number }[] = [];

  categories
    .filter((c) => c.parentId === parentId)
    .forEach((category) => {
      const prefix = level > 0 ? " ".repeat((level - 1) * 2) + "└─ " : "";
      result.push({ id: category.id, name: `${prefix}${category.name}`, level });
      const children = flattenCategories(categories, category.id, level + 1);
      result.push(...children);
    });

  return result;
};

export const ProductForm = ({ initialData, categories, storeId }: ProductFormProps) => {
  const flatCategories = flattenCategories(categories);
  const router = useRouter();
  const [isLoading, setIsLoading] = useState(false);
  const [activeTab, setActiveTab] = useState("basic");


  // Конвертируем images из initialData в формат ImageItem[]
  const initialImages: ImageItem[] = initialData?.images
    ? initialData.images.map((img: any, idx: number) => ({
        id: `img-${idx}-${Date.now()}`,
        url: typeof img === "string" ? img : img.url || "",
        alt: typeof img === "object" && img.alt ? img.alt : `Product image ${idx + 1}`,
      }))
    : [];

  const form = useForm<ProductInput>({
    resolver: zodResolver(productSchema) as any,
    defaultValues: initialData
      ? {
          ...initialData,
          price: Number(initialData.price),
          compareAtPrice: initialData.compareAtPrice ? Number(initialData.compareAtPrice) : undefined,
          stock: initialData.stock,
          attributes: initialData.attributes ? (Array.isArray(initialData.attributes) ? initialData.attributes : []) : [],
          variants: initialData.variants ? (Array.isArray(initialData.variants) ? initialData.variants : []) : [],
          tieredPricing: initialData.tieredPricing ? (Array.isArray(initialData.tieredPricing) ? initialData.tieredPricing : []) : [],
          images: initialData.images?.map((img: any) => typeof img === "string" ? img : img.url) || [],
        }
      : {
          name: "",
          description: "",
          price: 0,
          stock: 0,
          attributes: [],
          variants: [],
          tieredPricing: [],
          images: [],
          colors: [],
          tags: [],
        },
  });

  const { fields: attributeFields, append: appendAttribute, remove: removeAttribute } = useFieldArray({
    control: form.control,
    name: "attributes",
  });

  const { fields: variantFields, append: appendVariant, remove: removeVariant, replace: replaceVariants } = useFieldArray({
    control: form.control,
    name: "variants",
  });

  const { fields: tieredPricingFields, append: appendTieredPricing, remove: removeTieredPricing } = useFieldArray({
    control: form.control,
    name: "tieredPricing",
  });

  // Окремий стан для зобраень
  const [images, setImages] = useState<ImageItem[]>(initialImages);

  // Стан для мультимовних перекладів
  const [translations, setTranslations] = useState<TranslationsMap>({
    uk: { name: "", description: "", seoTitle: "", seoDescription: "" },
    en: { name: "", description: "", seoTitle: "", seoDescription: "" },
    pl: { name: "", description: "", seoTitle: "", seoDescription: "" },
  });

  // Ініціалізація перекладів з БД
  useEffect(() => {
    if (initialData?.translations) {
      const dbTranslations = initialData.translations as any[];
      const uk = dbTranslations.find((t) => t.locale === "uk") || {};
      const en = dbTranslations.find((t) => t.locale === "en") || {};
      const pl = dbTranslations.find((t) => t.locale === "pl") || {};

      setTranslations({
        uk: {
          name: uk.name || "",
          description: uk.description || "",
          seoTitle: uk.seoTitle || "",
          seoDescription: uk.seoDescription || "",
        },
        en: {
          name: en.name || "",
          description: en.description || "",
          seoTitle: en.seoTitle || "",
          seoDescription: en.seoDescription || "",
        },
        pl: {
          name: pl.name || "",
          description: pl.description || "",
          seoTitle: pl.seoTitle || "",
          seoDescription: pl.seoDescription || "",
        },
      });
    }
  }, [initialData?.translations]);

  const onSubmit = async (data: ProductInput) => {
    try {
      setIsLoading(true);
      // Конвертуємо ImageItem[] в масив URL для Prisma
      const imagesData = images.map((img) => img.url);

      const payload = {
        ...data,
        images: imagesData,
      };

      let productId = initialData?.id;

      if (initialData) {
        await updateProduct(initialData.id, storeId, payload);
        productId = initialData.id;
      } else {
        const result = await createProduct(storeId, payload);
        // Отримуємо ID щойно створеного продукту
        if ('id' in result && result.id) {
          productId = result.id;
        }
      }

      // Зберігаємо переклади для EN та PL
      if (productId) {
        // Зберігаємо англійський переклад
        if (translations.en.name || translations.en.description) {
          await saveProductTranslation(productId, "en", {
            name: translations.en.name,
            description: translations.en.description || null,
            seoTitle: translations.en.seoTitle || null,
            seoDescription: translations.en.seoDescription || null,
          });
        }

        // Зберігаємо польський переклад
        if (translations.pl.name || translations.pl.description) {
          await saveProductTranslation(productId, "pl", {
            name: translations.pl.name,
            description: translations.pl.description || null,
            seoTitle: translations.pl.seoTitle || null,
            seoDescription: translations.pl.seoDescription || null,
          });
        }
      }

      router.push(`/dashboard/${storeId}/products`);
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const generateVariants = () => {
    const attrs = form.getValues("attributes") || [];
    if (attrs.length === 0) return;

    const arrays = attrs.map((attr) => attr.values);

    // Cartesian product
    const cartesian = (...a: any[][]) =>
      a.reduce((a, b) => a.flatMap((d) => b.map((e) => [d, e].flat())));
    const combinations = attrs.length > 1 ? cartesian(...arrays) : arrays[0].map((v) => [v]);

    const newVariants = combinations.map((combo) => {
      const optionsRecord: Record<string, string> = {};
      attrs.forEach((attr, idx) => {
        optionsRecord[attr.name] = Array.isArray(combo) ? combo[idx] : combo;
      });
      // Створюємо назву варіації
      const name = Object.values(optionsRecord).join(" / ");
      return {
        id: undefined,
        name: name,
        sku: "",
        price: form.getValues("price"),
        stock: 0,
        options: optionsRecord,
      };
    });

    replaceVariants(newVariants);
  };

  // Обробник змін перекладів
  const handleTranslationsChange = (updatedTranslations: Partial<TranslationsMap>) => {
    setTranslations((prev) => ({
      ...prev,
      ...updatedTranslations,
    }));
  };

  return (
    <div className="bg-white shadow-sm rounded-lg border p-6">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold">{initialData ? "Редактировать товар" : "Новый товар"}</h2>
        <Button variant="outline" onClick={() => router.push(`/dashboard/${storeId}/products`)}>
          Отмена
        </Button>
      </div>

      <div className="flex space-x-4 mb-6 border-b">
        {["basic", "attributes", "variants", "tieredPricing"].map((tab) => (
          <button
            key={tab}
            onClick={(e) => {
              e.preventDefault();
              setActiveTab(tab);
            }}
            className={`pb-2 px-1 border-b-2 font-medium text-sm ${
              activeTab === tab
                ? "border-blue-500 text-blue-600"
                : "border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300"
            }`}
          >
            {tab === "basic" && "Основное"}
            {tab === "attributes" && "Атрибуты"}
            {tab === "variants" && "Вариации"}
            {tab === "tieredPricing" && "Оптовые цены"}
          </button>
        ))}
      </div>

      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
        {activeTab === "basic" && (
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">Название</label>
              <input
                {...form.register("name")}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
              />
            </div>
            <div>
              <div className="flex items-center justify-between mb-1">
                <label className="block text-sm font-medium text-gray-700">Описание</label>
                <AIWritingToolbar
                  storeId={storeId}
                  currentText={form.watch("description") || ""}
                  onGenerate={(text) => form.setValue("description", text)}
                  onRewrite={(text) => form.setValue("description", text)}
                  disabled={isLoading}
                />
              </div>
              <textarea
                {...form.register("description")}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
                rows={4}
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700">Цена</label>
                <input
                  type="number"
                  step="0.01"
                  {...form.register("price")}
                  className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Старая цена</label>
                <input
                  type="number"
                  step="0.01"
                  {...form.register("compareAtPrice")}
                  className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Остаток</label>
              <input
                type="number"
                {...form.register("stock")}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 border"
              />
