"use client";

import { useState, useRef } from "react";
import type { Product as PrismaProduct } from "@prisma/client";
import { updateProductInline, duplicateProductAction, generateSeoAction, importProducts } from "@/actions/product";
import { useRouter } from "next/navigation";
import { LayoutGrid, List as ListIcon, MoreVertical, Copy, Sparkles, Edit, Archive, ArchiveRestore, AlertCircle, Star, Plus, Download, Upload } from "lucide-react";
import { motion } from "framer-motion";
import Papa from "papaparse";
import { InlineEdit } from "@/components/ui/inline-edit";

type Product = PrismaProduct & {
  stock: number;
  images: string[];
  colors: string[];
  tags: string[];
  seoTitle: string | null;
  seoDescription: string | null;
  compareAtPrice?: number | null;
  isDraft: boolean;
};

type ProductStatus = "active" | "draft" | "archived";

function getProductStatus(product: Product): ProductStatus {
  if (product.isArchived) return "archived";
  if (product.isDraft) return "draft";
  return "active";
}

interface ProductsClientProps {
  data: Product[];
  storeId: string;
}

export function ProductsClient({ data, storeId }: ProductsClientProps) {
  const router = useRouter();
  const [view, setView] = useState<"list" | "grid">("list");
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editPrice, setEditPrice] = useState<number>(0);
  const [editStock, setEditStock] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);
  const [openDropdownId, setOpenDropdownId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleExportCSV = () => {
    const csvData = data.map((product) => ({
      ID: product.id,
      Название: product.name,
      Описание: product.description || "",
      Цена: product.price,
      "Старая цена": product.compareAtPrice || "",
      Остаток: product.stock,
      URL_изображения: product.imageUrl || "",
      Категория_ID: product.categoryId,
      Магазин_ID: product.storeId,
    }));

    const csv = Papa.unparse(csvData);
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", `products_export_${storeId}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleImportCSV = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    Papa.parse(file, {
      header: true,
      skipEmptyLines: true,
      complete: async (results) => {
        try {
          const parsedData = results.data as any[];
          const formattedData = parsedData.map((row) => ({
            name: row["Название"],
            description: row["Описание"],
            price: parseFloat(row["Цена"]),
            compareAtPrice: row["Старая цена"] ? parseFloat(row["Старая цена"]) : null,
            stock: parseInt(row["Остаток"], 10),
            imageUrl: row["URL_изображения"],
            categoryId: row["Категория_ID"],
          }));

          await importProducts(storeId, formattedData);
          router.refresh();
        } catch (error) {
          console.error("Ошибка при импорте:", error);
          alert("Произошла ошибка при импорте. Проверьте формат файла.");
        } finally {
          setIsLoading(false);
          if (fileInputRef.current) fileInputRef.current.value = "";
        }
      },
      error: (error) => {
        console.error("Ошибка парсинга CSV:", error);
        alert("Ошибка при чтении файла.");
        setIsLoading(false);
      }
    });
  };

  const handleInlineEditStart = (product: Product) => {
    setEditingId(product.id);
    setEditPrice(product.price);
    setEditStock(product.stock);
  };

  const handleInlineEditSave = async (id: string) => {
    try {
      setIsLoading(true);
      await updateProductInline(id, storeId, { price: editPrice, stock: editStock });
      setEditingId(null);
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleStatusChange = async (id: string, status: ProductStatus) => {
    try {
      setIsLoading(true);
      await updateProductInline(id, storeId, { 
        isArchived: status === "archived",
        isDraft: status === "draft"
      });
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
      setOpenDropdownId(null);
    }
  };

  // eslint-disable-next-line unused-imports/no-unused-vars
  const handleToggleArchive = async (id: string, isArchived: boolean) => {
    try {
      setIsLoading(true);
      await updateProductInline(id, storeId, { isArchived: !isArchived });
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
      setOpenDropdownId(null);
    }
  };

  const handleToggleFeatured = async (id: string, isFeatured: boolean) => {
    try {
      setIsLoading(true);
      await updateProductInline(id, storeId, { isFeatured: !isFeatured });
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDuplicate = async (id: string) => {
    try {
      setIsLoading(true);
      await duplicateProductAction(id, storeId);
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
      setOpenDropdownId(null);
    }
  };

  const handleGenerateSeo = async (id: string) => {
    try {
      setIsLoading(true);
      await generateSeoAction(id, storeId);
      router.refresh();
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
      setOpenDropdownId(null);
    }
  };

  return (
    <>
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Товары</h1>
          <p className="text-gray-500 mt-2">
            Управляйте товарами вашего магазина для витрины.
          </p>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex border border-gray-300 rounded-md overflow-hidden mr-2">
            <button
              onClick={handleExportCSV}
              className="p-2 bg-white hover:bg-gray-50 flex items-center gap-1 border-r border-gray-300"
              title="Экспорт в CSV"
              disabled={isLoading}
            >
              <Download className="h-4 w-4 text-gray-600" />
              <span className="text-sm font-medium text-gray-700 hidden sm:inline-block">Экспорт</span>
            </button>
            <button
              onClick={() => fileInputRef.current?.click()}
              className="p-2 bg-white hover:bg-gray-50 flex items-center gap-1"
              title="Импорт из CSV"
              disabled={isLoading}
            >
              <Upload className="h-4 w-4 text-gray-600" />
              <span className="text-sm font-medium text-gray-700 hidden sm:inline-block">Импорт</span>
            </button>
            <input
              type="file"
              accept=".csv"
              ref={fileInputRef}
              onChange={handleImportCSV}
              className="hidden"
            />
          </div>
          <div className="flex border border-gray-300 rounded-md overflow-hidden">
            <button
              onClick={() => setView("list")}
              className={`p-2 ${view === "list" ? "bg-gray-100" : "bg-white hover:bg-gray-50"}`}
              title="Список"
            >
              <ListIcon className="h-5 w-5 text-gray-600" />
            </button>
            <button
              onClick={() => setView("grid")}
              className={`p-2 border-l border-gray-300 ${view === "grid" ? "bg-gray-100" : "bg-white hover:bg-gray-50"}`}
              title="Сетка"
            >
              <LayoutGrid className="h-5 w-5 text-gray-600" />
            </button>
          </div>
          <button
            onClick={() => router.push(`/dashboard/${storeId}/products/new`)}
            className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
          >
            <Plus className="-ml-1 mr-2 h-5 w-5" />
            Добавить товар
          </button>
        </div>
      </div>

      {data.length === 0 ? (
        <div className="bg-white border border-gray-200 rounded-lg p-12 text-center text-gray-500 shadow-sm">
          <svg className="mx-auto h-12 w-12 text-gray-400 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
          </svg>
          У вас пока нет добавленных товаров.
        </div>
      ) : view === "list" ? (
        <div className="bg-white shadow-sm border border-gray-200 rounded-lg overflow-hidden overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Товар</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Цена</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Остаток</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Статус</th>
                <th scope="col" className="relative px-6 py-3"><span className="sr-only">Действия</span></th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {data.map((product) => (
                <tr key={product.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      <div className="h-10 w-10 flex-shrink-0 relative rounded-md overflow-hidden bg-gray-100">
                        {product.imageUrl ? (
                          <img src={product.imageUrl} alt={product.name} className="object-cover h-full w-full" />
                        ) : (
                          <svg className="h-6 w-6 text-gray-400 m-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                          </svg>
                        )}
                      </div>
                      <div className="ml-4 cursor-pointer" onClick={() => router.push(`/dashboard/${storeId}/products/${product.id}`)}>
                        <div className="text-sm font-medium text-gray-900 hover:text-blue-600">{product.name}</div>
                        <div className="text-sm text-gray-500 truncate max-w-[200px]">{product.seoTitle || product.description}</div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <InlineEdit
                      value={product.price}
                      type="price"
                      onSave={async (val) => {
                        setEditPrice(val);
                        setEditStock(product.stock);
                        await handleInlineEditSave(product.id);
                      }}
                      format={(val) => `$${val.toFixed(2)}`}
                    />
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <InlineEdit
                      value={product.stock}
                      type="stock"
                      onSave={async (val) => {
                        setEditStock(val);
                        setEditPrice(product.price);
                        await handleInlineEditSave(product.id);
                      }}
                    />
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <select
                      value={getProductStatus(product)}
                      onChange={(e) => handleStatusChange(product.id, e.target.value as ProductStatus)}
                      disabled={isLoading}
                      className={`text-xs font-semibold rounded-full px-2 py-1 border-0 bg-transparent cursor-pointer hover:opacity-80 focus:ring-2 focus:ring-blue-500 outline-none
