"use client";

import { useState, useEffect } from "react";
import { Globe } from "lucide-react";
import { TranslationPanel } from "@/components/dashboard/translation-panel";
import { Locale } from "@/actions/translations";

// Типи для мапи перекладів
export type TranslationsMap = {
  uk: {
    name: string;
    description: string;
    seoTitle: string;
    seoDescription: string;
  };
  en: {
    name: string;
    description: string;
    seoTitle: string;
    seoDescription: string;
  };
  pl: {
    name: string;
    description: string;
    seoTitle: string;
    seoDescription: string;
  };
};

// Початкові значення для мов
// eslint-disable-next-line unused-imports/no-unused-vars
const initialTranslation: TranslationsMap[keyof TranslationsMap] = {
  name: "",
  description: "",
  seoTitle: "",
  seoDescription: "",
};

// Конфігурація мов
const languages = [
  { code: "uk" as const, label: "Українська", flag: "🇺🇦" },
  { code: "en" as const, label: "English", flag: "🇬🇧" },
  { code: "pl" as const, label: "Polski", flag: "🇵🇱" },
] as const;

type LanguageCode = (typeof languages)[number]["code"];

interface ProductTranslationTabsProps {
  storeId: string;
  productId?: string | null;
  initialTranslations?: Partial<TranslationsMap>;
  baseName?: string;
  baseDescription?: string;
  baseSeoTitle?: string;
  baseSeoDescription?: string;
  onChange?: (translations: Partial<TranslationsMap>) => void;
}

export function ProductTranslationTabs({
  storeId,
  productId,
  initialTranslations,
  baseName = "",
  baseDescription = "",
  baseSeoTitle = "",
  baseSeoDescription = "",
  onChange,
}: ProductTranslationTabsProps) {
  const [activeTab, setActiveTab] = useState<LanguageCode>("uk");
  // eslint-disable-next-line unused-imports/no-unused-vars
  const [showAll, setShowAll] = useState(false);

  // Ініціалізація стану перекладів
  const [translations, setTranslations] = useState<TranslationsMap>({
    uk: {
      name: initialTranslations?.uk?.name || "",
      description: initialTranslations?.uk?.description || "",
      seoTitle: initialTranslations?.uk?.seoTitle || "",
      seoDescription: initialTranslations?.uk?.seoDescription || "",
    },
    en: {
      name: initialTranslations?.en?.name || "",
      description: initialTranslations?.en?.description || "",
      seoTitle: initialTranslations?.en?.seoTitle || "",
      seoDescription: initialTranslations?.en?.seoDescription || "",
    },
    pl: {
      name: initialTranslations?.pl?.name || "",
      description: initialTranslations?.pl?.description || "",
      seoTitle: initialTranslations?.pl?.seoTitle || "",
      seoDescription: initialTranslations?.pl?.seoDescription || "",
    },
  });

  // Оновлення стану при зміні початкових даних
  useEffect(() => {
    if (initialTranslations) {
      setTranslations({
        uk: {
          name: initialTranslations.uk?.name || "",
          description: initialTranslations.uk?.description || "",
          seoTitle: initialTranslations.uk?.seoTitle || "",
          seoDescription: initialTranslations.uk?.seoDescription || "",
        },
        en: {
          name: initialTranslations.en?.name || "",
          description: initialTranslations.en?.description || "",
          seoTitle: initialTranslations.en?.seoTitle || "",
          seoDescription: initialTranslations.en?.seoDescription || "",
        },
        pl: {
          name: initialTranslations.pl?.name || "",
          description: initialTranslations.pl?.description || "",
          seoTitle: initialTranslations.pl?.seoTitle || "",
          seoDescription: initialTranslations.pl?.seoDescription || "",
        },
      });
    }
  }, [initialTranslations]);

  // Обробник змін в полях
  // eslint-disable-next-line unused-imports/no-unused-vars
  const handleFieldChange = (
    locale: LanguageCode,
    field: keyof TranslationsMap[LanguageCode],
    value: string
  ) => {
    const updated = {
      ...translations,
      [locale]: {
        ...translations[locale],
        [field]: value,
      },
    };
    setTranslations(updated);
    onChange?.(updated);
  };

  // Підрахунок заповнених мов
  const filledCount = languages.filter((lang) => {
    const t = translations[lang.code];
    return t.name || t.description || t.seoTitle || t.seoDescription;
  }).length;

  const totalLanguages = languages.length;

  return (
    <div className="border rounded-lg overflow-hidden">
      {/* Header з вкладками мов */}
      <div className="flex items-center justify-between border-b bg-gray-50 px-4 py-3">
        <div className="flex items-center gap-2">
          <Globe className="w-4 h-4 text-gray-500" />
          <span className="text-sm font-medium text-gray-700">
            Мультимовні переклади
          </span>
          {/* Індикатор прогресу */}
          <span className="text-xs px-2 py-0.5 bg-blue-100 text-blue-700 rounded-full ml-2">
            {filledCount}/{totalLanguages} мов перекладено
          </span>
        </div>

        {/* Вкладки мов з кольоровими індикаторами */}
        <div className="flex">
          {languages.map(({ code, label, flag }) => {
            const t = translations[code];
            const isFilled = t.name || t.description || t.seoTitle || t.seoDescription;
            return (
              <button
                key={code}
                onClick={() => setActiveTab(code)}
                className={`px-4 py-2 text-sm font-medium transition-colors border-r flex items-center gap-2 ${
                  activeTab === code
                    ? "bg-white text-blue-600 border-b-2 border-b-blue-600"
                    : "text-gray-600 hover:bg-gray-100"
                }`}
              >
                <span className="text-lg">{flag}</span>
                <span>{label}</span>
                {/* Крапка-індикатор */}
                <span
                  className={`w-2 h-2 rounded-full ${
                    isFilled ? "bg-green-500" : "bg-yellow-400"
                  }`}
                />
              </button>
            );
          })}
        </div>
      </div>

      {/* Вміст вкладок */}
      <div className="p-4 bg-white">
        {languages.map(({ code, label, flag }) => {
          const isBaseLocale = code === "uk";
          const currentValue = translations[code];

          // Обробник змін для TranslationPanel
          const handlePanelChange = (updated: { name: string; description: string; seoTitle: string; seoDescription: string }) => {
            const newTranslations = {
              ...translations,
              [code]: {
                ...translations[code],
                name: updated.name,
                description: updated.description,
                seoTitle: updated.seoTitle,
                seoDescription: updated.seoDescription,
              },
            };
            setTranslations(newTranslations as TranslationsMap);
            onChange?.(newTranslations as Partial<TranslationsMap>);
          };

          return (
            <div key={code} className={activeTab === code ? "block" : "hidden"}>
              <TranslationPanel
                storeId={storeId}
                productId={productId}
                locale={code as Locale}
                label={label}
                flag={flag}
                baseName={baseName}
                baseDescription={baseDescription}
                baseSeoTitle={baseSeoTitle}
                baseSeoDescription={baseSeoDescription}
                value={currentValue}
                onChange={handlePanelChange}
                isBaseLocale={isBaseLocale}
              />
            </div>
          );
        })}
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Plus, Trash2, Save, Loader2 } from 'lucide-react';
import { saveTierPrices, getTierPrices } from '@/actions/tier-pricing';
import { toast } from 'sonner';

interface Tier {
  minQuantity: number;
  price: number;
}

interface TierPricingEditorProps {
  productId: string;
  storeId: string;
  basePrice: number;
}

export function TierPricingEditor({
  productId,
  storeId,
  basePrice,
}: TierPricingEditorProps) {
  const [tiers, setTiers] = useState<Tier[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  // Завантаження існуючих tiers
  useEffect(() => {
    async function loadTiers() {
      setIsLoading(true);
      try {
        const result = await getTierPrices(productId);
        if (result.success && result.data) {
          setTiers(result.data);
        }
      } catch (error) {
        console.error('Error loading tiers:', error);
      } finally {
        setIsLoading(false);
      }
    }

    loadTiers();
  }, [productId]);

  // Додавання нового tier
  const addTier = useCallback(() => {
    const lastMinQuantity = tiers.length > 0 ? tiers[tiers.length - 1].minQuantity : 0;
    setTiers((prev) => [
      ...prev,
      {
        minQuantity: lastMinQuantity + 1,
        price: basePrice,
      },
    ]);
  }, [tiers, basePrice]);

  // Видалення tier
  const removeTier = useCallback((index: number) => {
    setTiers((prev) => prev.filter((_, i) => i !== index));
  }, []);

  // Оновлення tier
  const updateTier = useCallback(
    (index: number, field: keyof Tier, value: number) => {
      setTiers((prev) =>
        prev.map((tier, i) =>
          i === index ? { ...tier, [field]: value } : tier
        )
      );
    },
    []
  );

  // Сортування tiers за minQuantity
  const sortedTiers = [...tiers].sort((a, b) => a.minQuantity - b.minQuantity);

  // Збереження
  const handleSave = async () => {
    if (tiers.length === 0) {
      toast.error('Додайте принаймні один рівень ціни');
      return;
    }

    // Перевірка на порожні значення
    for (const tier of tiers) {
      if (tier.minQuantity <= 0 || tier.price <= 0) {
        toast.error('Кількість та ціна мають бути додатними числами');
        return;
      }
    }

    setIsSaving(true);
    try {
      const result = await saveTierPrices(productId, storeId, tiers);
      if (result.success) {
        toast.success(result.message);
      } else {
        toast.error(result.error || 'Не вдалося зберегти');
      }
    // eslint-disable-next-line unused-imports/no-unused-vars
    } catch (error) {
      toast.error('Не вдалося зберегти гнучкі ціни');
    } finally {
      setIsSaving(false);
    }
  };

  if (isLoading) {
    return (
      <Card>
        <CardContent className="flex items-center justify-center py-8">
          <Loader2 className="h-6 w-6 animate-spin" />
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Гнучкі ціни (Tiered Pricing)</CardTitle>
        <CardDescription>
          Встановіть знижки за кількість. Наприклад: від 10 шт - 90 грн, від 50 шт - 85 грн.
        </CardDescription>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          {/* Поточна базова ціна */}
          <div className="rounded-lg bg-muted p-3">
            <p className="text-sm text-muted-foreground">
              Базова ціна: <span className="font-semibold">{basePrice} грн</span>
            </p>
          </div>

          {/* Таблиця tiers */}
          {sortedTiers.length > 0 ? (
            <div className="space-y-2">
              <div className="grid grid-cols-3 gap-2 text-sm font-medium text-muted-foreground">
                <div>Від кількості</div>
                <div>Ціна за одиницю</div>
                <div>Дії</div>
              </div>
              // eslint-disable-next-line unused-imports/no-unused-vars
              {sortedTiers.map((tier, index) => {
                const originalIndex = tiers.findIndex(
                  (t) => t.minQuantity === tier.minQuantity
                );
                return (
                  <div
                    key={tier.minQuantity}
                    className="grid grid-cols-3 gap-2 items-center"
                  >
                    <div>
                      <Input
                        type="number"
                        min="1"
                        value={tier.minQuantity}
                        onChange={(e) =>
                          updateTier(originalIndex, 'minQuantity', parseInt(e.target.value) || 0)
                        }
                        className="w-full"
                      />
                    </div>
                    <div>
                      <Input
                        type="number"
                        min="0.01"
                        step="0.01"
                        value={tier.price}
                        onChange={(e) =>
                          updateTier(originalIndex, 'price', parseFloat(e.target.value) || 0)
                        }
                        className="w-full"
                      />
                    </div>
                    <div>
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => removeTier(originalIndex)}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            <div className="text-center py-8 text-muted-foreground">
              Немає рівнів цін. Додайте перший рівень.
            </div>
          )}

          {/* Кнопки дій */}
          <div className="flex gap-2 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={addTier}
              disabled={isSaving}
            >
              <Plus className="h-4 w-4 mr-2" />
              Додати рівень
            </Button>
            <Button
              type="button"
              onClick={handleSave}
              disabled={isSaving || tiers.length === 0}
              className="ml-auto"
            >
              {isSaving ? (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              ) : (
                <Save className="h-4 w-4 mr-2" />
              )}
              Зберегти
            </Button>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

